// Some portions generated by Co-Pilot
"use client";

import React, { useState } from "react";
import { Link } from "@/i18n/navigation";
import Image from "next/image";
import { useTranslations, useLocale } from "next-intl";
import { sendDownloadEvent } from "@/utils/gtag";
import type { BinaryAssetView } from "@/types/temurin";
import { getSizeMB, getExtension } from "@/utils/temurin";
import { FaWindows, FaApple } from "react-icons/fa";
import { FcLinux } from "react-icons/fc";
import { SiAlpinelinux } from "react-icons/si";
import { AixIcon, SolarisIcon } from "@/components/Common/Icon";
import { BsCopy, BsDownload } from "react-icons/bs";
import AnimatedPlaceholder from "@/components/Common/AnimatedPlaceholder";
import { MdVerifiedUser } from "react-icons/md";
import { useAttestations } from "@/hooks/useAttestations";

interface ReleaseResultsProps {
  releases: BinaryAssetView[];
  isLoading: boolean;
  openModalWithChecksum: (checksum: string) => void;
}

const osIcons = {
  windows: FaWindows,
  mac: FaApple,
  "alpine-linux": SiAlpinelinux,
  linux: FcLinux,
  aix: AixIcon,
  solaris: SolarisIcon,
};

const ReleaseResults: React.FC<ReleaseResultsProps> = ({
  releases,
  isLoading,
  openModalWithChecksum,
}) => {
  const t = useTranslations("Temurin.Releases.ReleaseResults");
  const locale = useLocale();

  const [selectedArchitectures, setSelectedArchitectures] = useState<
    Record<string, string>
  >({});
  const [selectedPackageTypes, setSelectedPackageTypes] = useState<
    Record<string, string>
  >({});

  const allChecksums = React.useMemo(() => {
    const checksums: string[] = [];
    releases.forEach((view) => {
      if (view.binary?.package?.checksum)
        checksums.push(view.binary.package.checksum);
      if (view.binary?.installer?.checksum)
        checksums.push(view.binary.installer.checksum);
    });
    return checksums;
  }, [releases]);

  const releaseName = releases[0]?.release_name;

  const { attestations, isLoading: attestationsLoading } = useAttestations(
    releaseName,
    allChecksums,
  );

  const hasAttestation = (checksum?: string | null): boolean => {
    if (attestationsLoading || !checksum) return false;
    return attestations[checksum] !== undefined;
  };

  if (isLoading) {
    return (
      <section className="py-4" data-testid="release-results-loading">
        <div className="space-y-4">
          {[1, 2, 3].map((index) => (
            <div
              key={index}
              className="flex justify-between border flex-wrap border-[#554772] rounded-[16px] !bg-[#200E46] items-start p-4 lg:p-5 animate-pulse"
              data-testid={`loading-skeleton-${index}`}
            >
              <div className="w-full lg:w-[45%] flex flex-col">
                <AnimatedPlaceholder>
                  <div className="p-4 bg-[#2B1A4F] flex flex-col rounded-[16px] gap-4">
                    <div className="flex justify-between items-center">
                      <div className="flex gap-3 justify-start items-center">
                        <div className="w-6 h-6 bg-gray-600 rounded-full animate-pulse"></div>
                        <div className="h-5 bg-gray-600 rounded w-20 animate-pulse"></div>
                      </div>
                      <div className="flex gap-3">
                        <div className="h-5 bg-gray-600 rounded w-14 animate-pulse"></div>
                      </div>
                    </div>
                    <div className="h-8 bg-gray-600 rounded-full animate-pulse"></div>
                  </div>
                </AnimatedPlaceholder>
              </div>
              <div className="flex flex-col w-full lg:w-[50%] mt-6 lg:mt-0">
                <div className="h-5 bg-gray-600 rounded w-48 mb-4 animate-pulse"></div>
                <div className="space-y-3">
                  <div className="h-12 bg-gray-600 rounded-xl animate-pulse"></div>
                  <div className="h-12 bg-gray-600 rounded-xl animate-pulse"></div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>
    );
  }

  if (releases.length === 0) {
    return (
      <section className="py-8" data-testid="release-results-empty">
        <div className="flex justify-center items-center min-h-[400px] border border-[#554772] rounded-[24px] bg-[#200E46] p-8">
          <div className="text-center space-y-6 max-w-md">
            <div className="w-24 h-24 mx-auto bg-gradient-to-br from-[#2B1A4F] to-[#3E3355] rounded-full flex items-center justify-center">
              <svg
                className="w-12 h-12 text-gray-400"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
                data-testid="empty-state-icon"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={1.5}
                  d="M9.75 9.75l4.5 4.5m0-4.5l-4.5 4.5M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
                />
              </svg>
            </div>
            <div className="space-y-2">
              <h3
                className="text-2xl font-semibold text-white"
                data-testid="empty-state-title"
              >
                {t("no-releases-found")}
              </h3>
              <p
                className="text-gray-400 leading-relaxed"
                data-testid="empty-state-description"
              >
                {t("no-releases-found-description")}
              </p>
            </div>
          </div>
        </div>
      </section>
    );
  }

  // Group BinaryAssetView[] by os → architecture
  const groupedReleases = releases.reduce<
    Record<string, Record<string, BinaryAssetView[]>>
  >((acc, view) => {
    const os = view.binary?.os ?? "unknown";
    const arch = view.binary?.architecture ?? "unknown";
    if (!acc[os]) acc[os] = {};
    if (!acc[os][arch]) acc[os][arch] = [];
    acc[os][arch].push(view);
    return acc;
  }, {});

  const handleArchSelection = (os: string, arch: string) => {
    setSelectedArchitectures((prev) => ({ ...prev, [os]: arch }));
  };

  const handlePackageTypeSelection = (
    os: string,
    arch: string,
    packageType: string,
  ) => {
    setSelectedPackageTypes((prev) => ({
      ...prev,
      [`${os}-${arch}`]: packageType,
    }));
  };

  const getPackageType = (os: string, arch: string) =>
    selectedPackageTypes[`${os}-${arch}`] || "jdk";

  const osOrder = ["linux", "windows", "mac", "alpine-linux", "aix", "solaris"];

  const sortedOSEntries = Object.entries(groupedReleases).sort(
    ([osA], [osB]) => {
      const indexA = osOrder.indexOf(osA);
      const indexB = osOrder.indexOf(osB);
      if (indexA === -1 && indexB === -1) return 0;
      if (indexA === -1) return 1;
      if (indexB === -1) return -1;
      return indexA - indexB;
    },
  );

  return (
    <section className="py-4" data-testid="release-results-content">
      <div className="space-y-4">
        {sortedOSEntries.map(([os, architectures]) => {
          const IconComponent = osIcons[os as keyof typeof osIcons] || FcLinux;
          const architectureList = Object.keys(architectures).sort((a, b) =>
            b.localeCompare(a),
          );

          const selectedArch =
            selectedArchitectures[os] ||
            (architectureList.includes("x64") ? "x64" : architectureList[0]);

          const viewGroup = architectures[selectedArch] || [];
          const firstView = viewGroup[0];
          const releaseDate = firstView?.binary?.updated_at;

          return (
            <div
              key={os}
              className="flex justify-between border flex-wrap border-[#554772] rounded-[24px] !bg-[#200E46] items-start p-4 lg:p-6"
              data-testid={`release-card-${os}`}
            >
              <div className="w-full lg:w-[45%] flex flex-col">
                <div>
                  <div className="p-4 bg-[#2B1A4F] flex flex-col rounded-[24px] gap-4">
                    <div className="flex justify-between items-center">
                      <div className="flex gap-4 justify-start items-center">
                        <IconComponent size={30} />
                        <h5
                          className="text-2xl font-semibold leading-[32px]"
                          data-testid={`os-title-${os}`}
                        >
                          {os === "mac"
                            ? "macOS"
                            : os.charAt(0).toUpperCase() + os.slice(1)}
                        </h5>
                      </div>
                      <div
                        className="flex gap-4"
                        data-testid={`architecture-tabs-${os}`}
                      >
                        {architectureList.map((arch) => (
                          <button
                            key={arch}
                            onClick={() => handleArchSelection(os, arch)}
                            data-testid={`arch-tab-${os}-${arch}`}
                          >
                            <span
                              className={`py-2 w-full text-base font-normal leading-6 outline-hidden cursor-pointer transition-all duration-200 ease-in-out ${
                                selectedArch === arch
                                  ? "border-primary border-b-[2px] text-white"
                                  : "text-[#8a809e] border-transparent border-b"
                              }`}
                            >
                              {arch}
                            </span>
                          </button>
                        ))}
                      </div>
                    </div>

                    <div
                      className="flex gap-2 mt-1"
                      data-testid={`package-type-buttons-${os}-${selectedArch}`}
                    >
                      <button
                        className={`px-4 py-2 text-sm font-medium rounded-full border transition-colors ${
                          getPackageType(os, selectedArch) === "jdk"
                            ? "border-[#FF1464] text-[#FF1464] bg-[#2B1A4F]"
                            : "border-gray-500 text-gray-300 hover:border-gray-300"
                        }`}
                        onClick={() =>
                          handlePackageTypeSelection(os, selectedArch, "jdk")
                        }
                        data-testid={`jdk-button-${os}-${selectedArch}`}
                      >
                        JDK
                      </button>
                      <button
                        className={`px-4 py-2 text-sm font-medium rounded-full border transition-colors ${
                          getPackageType(os, selectedArch) === "jre"
                            ? "border-[#FF1464] text-[#FF1464] bg-[#2B1A4F]"
                            : "border-gray-500 text-gray-300 hover:border-gray-300"
                        }`}
                        onClick={() =>
                          handlePackageTypeSelection(os, selectedArch, "jre")
                        }
                        data-testid={`jre-button-${os}-${selectedArch}`}
                      >
                        JRE
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex flex-col w-full lg:w-[50%] mt-8 lg:mt-0">
                <h5
                  className="pb-6 border-b-[1px] text-2xl font-semibold border-[#3E3355]"
                  data-testid={`release-header-${os}`}
                >
                  {`Temurin ${firstView?.release_name ?? ""} - ${
                    releaseDate
                      ? new Date(releaseDate).toLocaleDateString(locale, {
                          day: "2-digit",
                          month: "2-digit",
                          year: "numeric",
                        })
                      : ""
                  }`}
                </h5>

                {/* Package download rows */}
                {viewGroup
                  .filter((view) => {
                    const imgType = (
                      view.binary?.image_type ?? ""
                    ).toLowerCase();
                    const selected = getPackageType(
                      os,
                      selectedArch,
                    ).toLowerCase();
                    return selected === "any" || imgType === selected;
                  })
                  .map((view, idx) => {
                    const b = view.binary;
                    const pkgLink = (b?.package?.link ?? "") as string;
                    const pkgChecksum = b?.package?.checksum ?? "";
                    const pkgSize = getSizeMB(b?.package?.size);
                    const pkgExt = getExtension(b?.package?.name).toUpperCase();
                    const imgType = (b?.image_type ?? "").toUpperCase();

                    return (
                      <div
                        key={`${os}-${selectedArch}-${imgType}-${idx}`}
                        className="text-white w-[100%] py-6 border-b-[1px] border-[#3E3355]"
                        data-testid={`binary-row-${os}-${selectedArch}-${imgType}-${idx}`}
                      >
                        <div className="flex justify-between w-full items-center">
                          <div className="flex items-center gap-2">
                            <span className="cursor-pointer group">
                              <Link
                                href={{
                                  pathname: "/download",
                                  query: { link: pkgLink, vendor: "Adoptium" },
                                }}
                                onClick={() =>
                                  sendDownloadEvent({
                                    link: pkgLink,
                                    os,
                                    arch: selectedArch,
                                    pkg_type: imgType,
                                    version: view.release_name ?? "",
                                    vendor: "temurin",
                                  })
                                }
                                data-testid={`download-link-${os}-${selectedArch}-${imgType}-${idx}`}
                              >
                                <BsDownload size={20} />
                              </Link>
                            </span>
                            <h5
                              className="text-base font-normal"
                              data-testid={`binary-info-${os}-${selectedArch}-${imgType}-${idx}`}
                            >
                              {`${pkgExt}, ${pkgSize} MB`}
                            </h5>
                            <MdVerifiedUser
                              size={30}
                              style={{ color: "rgb(83, 127, 185)" }}
                              data-toggle="tooltip"
                              data-placement="bottom"
                              title={t("this-build-is-jck-certified")}
                            />
                            <Link href="/aqavit/">
                              <Image
                                src="/images/icons/aqavit-icon.png"
                                width="25"
                                height="25"
                                alt="AQAvit logo"
                                data-toggle="tooltip"
                                data-placement="bottom"
                                title={t("this-build-is-aqavit-verified")}
                                className="img-fluid mb-0"
                              />
                            </Link>
                            {hasAttestation(pkgChecksum) && (
                              <Image
                                src="/images/icons/reproduced-verified.svg"
                                width={25}
                                height={25}
                                alt="Reproducibility Verified"
                                data-toggle="tooltip"
                                data-placement="bottom"
                                title="This build is reproduced by a 3rd party"
                                className="img-fluid mb-0"
                              />
                            )}
                          </div>
                          <div className="flex items-center gap-2">
                            <span className="cursor-pointer group">
                              <a
                                href="#"
                                onClick={(e) => {
                                  e.preventDefault();
                                  if (pkgChecksum)
                                    openModalWithChecksum(pkgChecksum);
                                }}
                                data-testid={`checksum-link-${os}-${selectedArch}-${imgType}-${idx}`}
                              >
                                <BsCopy size={20} />
                              </a>
                            </span>
                            <h5 className="text-base font-normal">
                              {t("checksum")}
                            </h5>
                          </div>
                        </div>
                      </div>
                    );
                  })}

                {/* Installer rows */}
                {viewGroup
                  .filter((view) => {
                    if (!view.binary?.installer?.link) return false;
                    const imgType = (
                      view.binary?.image_type ?? ""
                    ).toLowerCase();
                    const selected = getPackageType(
                      os,
                      selectedArch,
                    ).toLowerCase();
                    return selected === "any" || imgType === selected;
                  })
                  .map((view, idx) => {
                    const b = view.binary;
                    const instLink = (b?.installer?.link ?? "") as string;
                    const instChecksum = b?.installer?.checksum ?? "";
                    const instSize = getSizeMB(b?.installer?.size);
                    const instExt =
                      getExtension(b?.installer?.name).toUpperCase() ||
                      "INSTALLER";
                    const imgType = (b?.image_type ?? "").toUpperCase();

                    return (
                      <div
                        key={`${os}-${selectedArch}-${imgType}-installer-${idx}`}
                        className="text-white w-[100%] py-6 border-b-[1px] border-[#3E3355]"
                      >
                        <div className="flex justify-between w-full items-center">
                          <div className="flex items-center gap-2">
                            <span className="cursor-pointer group">
                              <Link
                                href={{
                                  pathname: "/download",
                                  query: { link: instLink, vendor: "Adoptium" },
                                }}
                                onClick={() =>
                                  sendDownloadEvent({
                                    link: instLink,
                                    os,
                                    arch: selectedArch,
                                    pkg_type: "installer",
                                    version: view.release_name ?? "",
                                    vendor: "temurin",
                                  })
                                }
                              >
                                <BsDownload size={20} />
                              </Link>
                            </span>
                            <h5 className="text-base font-normal">
                              {`${instExt}, ${instSize} MB`}
                            </h5>
                            <MdVerifiedUser
                              size={30}
                              style={{ color: "rgb(83, 127, 185)" }}
                              data-toggle="tooltip"
                              data-placement="bottom"
                              title={t("this-build-is-jck-certified")}
                            />
                            <Link href="/aqavit/">
                              <Image
                                src="/images/icons/aqavit-icon.png"
                                width="25"
                                height="25"
                                alt="AQAvit logo"
                                data-toggle="tooltip"
                                data-placement="bottom"
                                title="This build is AQAvit Verified"
                                className="img-fluid mb-0"
                              />
                            </Link>
                            {hasAttestation(instChecksum) && (
                              <Image
                                src="/images/icons/reproduced-verified.svg"
                                width={25}
                                height={25}
                                alt="Reproducibility Verified"
                                title="This build is reproduced by a 3rd party"
                              />
                            )}
                          </div>
                          <div className="flex items-center gap-2">
                            <span className="cursor-pointer group">
                              <a
                                href="#"
                                onClick={(e) => {
                                  e.preventDefault();
                                  if (instChecksum)
                                    openModalWithChecksum(instChecksum);
                                }}
                              >
                                <BsCopy size={20} />
                              </a>
                            </span>
                            <h5 className="text-base font-normal">
                              {t("checksum")}
                            </h5>
                          </div>
                        </div>
                      </div>
                    );
                  })}
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
};

export default ReleaseResults;

